/// <summary>
/// Initilazing from packing slip trans
/// </summary>
/// <param name = "_custPackingSlipTrans">CustPackingSlipTrans buffer</param>
void initFromCustPackingSlipTrans(CustPackingSlipTrans _custPackingSlipTrans)
{
    next initFromCustPackingSlipTrans(_custPackingSlipTrans);

    CustPackingSlipJour     etgCustPackingSlipJour = _custPackingSlipTrans.custPackingslipJour();

    this.ETG_BLDate     = etgCustPackingSlipJour.BOLDate;
    this.ETG_BLnumber   = etgCustPackingSlipJour.BOLNo;
}
